CustomField.formula:
IF(
ISBLANK( IF(RecordType.DeveloperName = "Surgeries", Spincal__r.tafnitID__c , Accession_Number__c) ),'Accession_Number', IF( ISBLANK(Date_of_appointment__c) ,'Date_of_appointment', IF( ISBLANK(Time_of_appointment__c) ,'Time_of_appointment', IF( ISBLANK(Calendar__r.ReminderId__c) ,'Calendar', IF( ISBLANK(Medical_Procedure__r.Domain__r.DomainReminderCode__c) ,'DomainReminderCode', IF( ISBLANK(Patient_Account__r.FirstName) ,'FirstName', IF( ISBLANK(PayerFactor__r.Code_Payer_Tizkurit__c) ,'PayerFactor', IF( ISBLANK(Medical_Procedure__r.Action_code_to_remember__c) ,'Procedure_Action_code_to_remember', IF( ISBLANK(Time_of_Tizkorit__c) ,'Time_of_Tizkorit', IF( ISBLANK(Site__r.Code_Tizkurit__c) ,'Site_Code_Tizkurit', IF( ISBLANK(Date_for_tizkorit_reminder__c) ,'Date_for_tizkorit_reminder', IF( ISBLANK(Patient_Account__r.Phone) && ISBLANK(Patient_Account__r.SMS_Phone_Number__c) && ISBLANK(Patient_Account__r.PersonContact.OtherPhone) ,'Phone','GOOD') ))))))))))
)
